import React from "react";
import "./Services.css";

const services = {
  "🏨 Travel & Stay": [
    {
      id: 1,
      name: "Hotel Booking",
      description: "Book top-rated hotels and villas across the world.",
      image: "https://images.unsplash.com/photo-1568605114967-8130f3a36994?fit=crop&w=800&q=80",
    },
    {
      id: 2,
      name: "Tour Guides",
      description: "Explore cities like a local with expert guides.",
      image: "https://images.unsplash.com/photo-1438761681033-6461ffad8d80?fit=crop&w=800&q=80",
    },
  ],

  "💄 Beauty & Lifestyle": [
    {
      id: 3,
      name: "Makeup & Salon",
      description: "Book beauty, hair, and makeup professionals instantly.",
      image: "https://images.unsplash.com/photo-1508214751196-bcfd4ca60f91?fit=crop&w=800&q=80",
    },
  ],

  "🚗 Transport & Tours": [
    {
      id: 4,
      name: "Car Rentals",
      description: "Choose cars for road trips, city rides, or long drives.",
      image: "https://images.unsplash.com/photo-1533473359331-0135ef1b58bf?fit=crop&w=800&q=80",
    },
  ],
};

function Services() {
  return (
    <div className="services-container">
      <h1 className="services-title">Our Services</h1>

      {Object.entries(services).map(([category, items]) => (
        <section key={category} className="services-section">
          <h2 className="services-category">{category}</h2>

          <div className="services-grid">
            {items.map((service) => (
              <div className="service-card" key={service.id}>
                <img src={service.image} alt={service.name} className="service-image" />
                <div className="service-info">
                  <h3 className="service-name">{service.name}</h3>
                  <p className="service-description">{service.description}</p>
                  <button className="learn-more-btn">Learn More</button>
                </div>
              </div>
            ))}
          </div>
        </section>
      ))}
    </div>
  );
}

export default Services;
